trait WatermarkProperties {
  def partition: String
  def runId: String
  def timestamp: Timestamp = new Timestamp(System.currentTimeMillis())
}

trait WatermarkPropertiesHandler[T <: WatermarkProperties] {

  def createWatermarkDF(watermarkProperties: T): DataFrame = {
    val schema = StructType(Array(
      StructField("Partition", StringType, nullable = false),
      StructField("RunId", StringType, nullable = false),
      StructField("UpdatedAt", TimestampType, nullable = false)
    ))

    val watermarkRecord = Seq(Row(watermarkProperties.partition,watermarkProperties.runId,watermarkProperties.timestamp))
    val spark = SparkSession.getActiveSession.get
    spark.createDataFrame(watermarkRecord.asJava, schema)
  }

  def apply(row: Row): T 
}

case class DefaultWatermarkProperties(partition: String, runId: String) extends WatermarkProperties
case class DefaultWatermarkPropertiesHandler() extends WatermarkPropertiesHandler[DefaultWatermarkProperties] {
  override def apply(row: Row): DefaultWatermarkProperties = {
    val partition = row.getAs[String]("Partition")
    val runId = row.getAs[String]("RunId")
    DefaultWatermarkProperties(partition, runId)
  }
}


class WatermarkRepository[P <: WatermarkProperties, H <: WatermarkPropertiesHandler[P]](spark: SparkSession, basePath: String) {
  private val filePath: String = basePath + "/adx-watermark"
  private val maxWatermarkPerRunId: Int = 100

  def save(wmProperties: List[P], wmPropertiesHandler: H): Unit = {
    val newWatermarkDF = wmProperties.map(wmPropertiesHandler.createWatermarkDF).reduce(_ union _)
    val allWatermarkDF = if (this.isFileExist()) this.getAll().union(newWatermarkDF) else newWatermarkDF
    val filteredWatermarks = getLatestN(allWatermarkDF, maxWatermarkPerRunId).collectAsList()
    val filteredWatermarkDF = spark.createDataFrame(filteredWatermarks, allWatermarkDF.schema)
    filteredWatermarkDF.repartition(1).write.option("header", "true").mode(SaveMode.Overwrite).csv(filePath)
    println("------------------------[Watermark] saved ---------------------")
  }

  def save(wmProperties: P, wmPropertiesHandler: H): Unit = {
    println(s"------------------------[Watermark] saving for partition: ${wmProperties.partition} and runid : ${wmProperties.runId} at file $filePath ---------------------")
    this.save(List(wmProperties), wmPropertiesHandler)
  }

  def hasMatchingWatermark(runId: String, partition: String): Boolean = {
    if (!isFileExist()) {
      false
    } else {
      val existingWatermarkDF = getAll()
      existingWatermarkDF
        .filter(
          col("RunId") === runId &&
            col("Partition") === partition
        )
        .limit(1)
        .count() > 0
    }
  }

  private def getAll(): DataFrame = {
    spark.read.option("sep", ",").option("header", "true").option("inferSchema", "true").csv(filePath)
  }

  private def isFileExist(): Boolean = {
    notebookutils.fs.exists(filePath)
  }

  private def getLatestN(watermarkDF: DataFrame, n: Int): DataFrame = {
    val windowSpec = Window.partitionBy("Partition").orderBy(desc("RunId"))
    watermarkDF.withColumn("rank", rank() over windowSpec).filter(col("rank") <= lit(n)).drop(col("rank"))
  }
}

