object HttpClient {
  private val cm = new PoolingHttpClientConnectionManager()
  cm.setMaxTotal(Constants.MAX_NUMBER_OF_CONNECTIONS)

  private val httpclient = HttpClients
    .custom()
    .setConnectionManager(cm)
    .build()

  private val requestConfig =
    RequestConfig.custom
      .setConnectTimeout(Constants.CONNECTION_TIMEOUT * 1000)
      .setConnectionRequestTimeout(Constants.CONNECTION_REQUEST_TIMEOUT * 1000)
      .setSocketTimeout(Constants.SOCKET_TIMEOUT * 1000)
      .build

  def getHttpClient(): CloseableHttpClient = httpclient

  def getRequestConfig() = requestConfig
}

class KustoCommandManager(cluster: String) {
  val route = "/v1/rest/mgmt"

  def execute(query: String): (String, Int) = {
    val url = s"https://$cluster.kusto.windows.net$route"
    println(s"Cluster url : $url")

    val request = new HttpPost(url)
    request.setConfig(HttpClient.getRequestConfig())
    var response: CloseableHttpResponse = null
    try {
      val entity = new StringEntity(query)
      request.setEntity(entity)
      request.setHeader("Accept", "application/json")
      request.setHeader("Content-type", "application/json")
      setAuthorization(request)
      response = HttpClient.getHttpClient().execute(request)

      // Handle response
      val responseString = EntityUtils.toString(response.getEntity(), "UTF-8");
      println("Response Code: " + response.getStatusLine().getStatusCode());
      //println("Response Body: " + responseString);

      (responseString, response.getStatusLine().getStatusCode())
    }
    catch {
      case e: Exception =>
        println(e.getMessage())
        throw new Exception("Unable to execute kusto query.", e)
    }
    finally {
      if (response != null) {
        response.close()
      }
      if (request != null)
        request.releaseConnection()
    }
  }

  private def setAuthorization(request: HttpRequest): Unit = {
    request.setHeader("Authorization", "Bearer " + mssparkutils.credentials.getToken("AzureDataExplorer"))
  }
}

object KustoCommandBuilder {

  def buildQuery(commandType: String, table: String, destinationTable: String = null, viewName: String = null, tablesForViewcreation: String = null): String = {

    val kqlCommand = commandType.toLowerCase match {
      case "clear" => s".drop extents from $table"
      case "replaceextents" => s".replace extents in table  $destinationTable <| {.show table $destinationTable extents},{.show table $table  extents}"
      case "createtable" => s".set $destinationTable <| $table | where false" // Create destination_table from table
      case "droptable" => s".drop table $table ifexists"
      case "droptables" => s".drop tables ($table, $destinationTable) ifexists"
      case "createview" => s".create-or-alter function with (view=true, skipvalidation = true) $viewName() {$table}"
      case "createviewformutipletables" => s".create-or-alter function with (view=true, skipvalidation = true) $viewName() {union $tablesForViewcreation}"
      case "altertablefolder" => s""".alter table $table folder 'internal'"""
      case "renametables" => s".rename tables $destinationTable=$table ifexists , $table=$destinationTable"
      case "restricttableviewaccess" => s".alter table $table policy restricted_view_access true"
      case "unrestricttableviewaccess" => s".alter table $table policy restricted_view_access false"
      case other => throw new IllegalArgumentException(s"Unsupported command type: $other")
    }
    println(s"kqlCommand : " + kqlCommand)
    kqlCommand
  }

  def buildKustoJson(database: String, query: String): String = {
    val jsonString =
      s"""{
         |  "db": "$database",
         |  "csl": "$query"
         |}""".stripMargin
    println("Request body" + jsonString)
    jsonString
  }

