//Class to do Kusto View Creation
class KustoViewCreator(cluster: String,
                       database: String,
                       isPartitionedDataset: Boolean) {

  def createViewForDataset(datasetName: String,
                           partitionListToBeLoaded: List[PartitionStorageInfo],
                           mainTablePrefix: String,
                           viewName: String): Unit = {
    println(s"================ Create view $viewName ==================================")

    if (isPartitionedDataset) {
      createPartitionedView(datasetName, partitionListToBeLoaded, mainTablePrefix, viewName)
    } else {
       createNonPartitionedView(datasetName, mainTablePrefix, viewName)
    }
  }

  private def createPartitionedView(datasetName: String,
                              partitionListToBeLoaded: List[PartitionStorageInfo],
                              mainTablePrefix: String,
                              viewName: String): Unit = {
    val tablesForViewcreation =
    partitionListToBeLoaded
    .map(info => s"${mainTablePrefix}_${info.partition}")
    .mkString(",")

    val viewCreateQuery =
      KustoCommandBuilder.buildKustoJson(
        database,
        KustoCommandBuilder.buildQuery(
          "createviewformutipletables",
          mainTablePrefix,
          tablesForViewcreation = tablesForViewcreation,
          viewName = viewName
        )
      )
    val (response, status) = new KustoCommandManager(cluster).execute(viewCreateQuery)
    if (status != 200) {
      println(response)
      throw new Exception("Kusto view creation failed. StatusCode: " + status)
    }
  }

  private def createNonPartitionedView(datasetName: String,
                                 mainTablePrefix: String,
                                 viewName: String): Unit = {
    val viewCreateQuery =
      KustoCommandBuilder.buildKustoJson(
        database,
        KustoCommandBuilder.buildQuery("createview", table = mainTablePrefix, viewName = viewName)
      )

    val (response, status) = new KustoCommandManager(cluster).execute(viewCreateQuery)
    if (status != 200) {
      println(response)
      throw new Exception("Kusto view creation failed. StatusCode: " + status)
    }
  }
}

// Class to do Kusto Ingestion
class KustoIngestionManager(spark: SparkSession,
                            cluster: String,
                            database: String,
                            stagingTable: String,
                            mainTable: String
                           ) {

  /** Helper method to run Kusto commands */
  private def runKustoCommand(query: String, errorMsg: String): Unit = {
    val (response, statusCode) = new KustoCommandManager(cluster).execute(query)
    if (statusCode != 200) {
      throw new Exception(s"$errorMsg. StatusCode: $statusCode, Response: $response")
    }
  }

  /** Helper to check existence of a Kusto table */
  private def isTableExists(table: String): Boolean = {
    println(s"Check if $table exists")
    try {
      spark.read
        .format("com.microsoft.kusto.spark.synapse.datasource")
        .option("kustoDatabase", database)
        .option("kustoCluster", cluster)
        .option("kustoQuery", s"$table | count")
        .load()

      true
    } catch {
      case e: Exception =>
        val errorMsg = e.getMessage
        println(s"Error reading from Kusto for table '$table': $errorMsg")

        if (errorMsg.contains("Semantic error: SEM0100: 'count' operator: Failed to resolve table or column expression named")) {
          println("Table does not exist.")
          false
        } else {
          throw new RuntimeException(s"isTableExists failed for table '$table': $errorMsg", e)
        }
    }
  }

  private def validateKustoRowCount(table: String, storageRowCount: Long): Unit = {

    println(s"================ Validate the row count of Kusto and storage for table $table=================")

    val kustoRowCountDF = spark.read
      .format("com.microsoft.kusto.spark.synapse.datasource")
      .option("kustoDatabase", database)
      .option("kustoCluster", cluster)
      .option("kustoQuery", s"$table | count")
      .load()

    val kustoRowCount = kustoRowCountDF.collect()(0).getLong(0)

    println(s"Number of rows in storage : $storageRowCount = Kusto : $kustoRowCount")

    if (storageRowCount != kustoRowCount) {
      println(s"The number of rows in storage : $storageRowCount != Kusto : $kustoRowCount")
      throw new RuntimeException(s"Row count validation failed on table $table!!!")
    }
  }

  /** Main ingestion function */
  def ingest(storagePaths: Seq[String]): Unit = {
    // Read the  Storage blob
    val startTime = System.nanoTime()

    // Drop the staging table
    println(s"================Drop  table: $stagingTable ==================================")
    runKustoCommand(KustoCommandBuilder.buildKustoJson(database,
      KustoCommandBuilder.buildQuery("droptable", table = stagingTable)),
      s"Kusto command failed while dropping $stagingTable")

    // Read from storage paths
    println(s"================Read from storage paths: ${storagePaths.mkString(",")} ==================================")

    val dfStorageRead = spark.read
      .format("parquet")
      .load(storagePaths: _*)

    val storageRowCount = dfStorageRead.count()
    val actualInputDFPartitions: Int = dfStorageRead.rdd.getNumPartitions
    println(s"actualInputDFPartitions: $actualInputDFPartitions,storageRowCount $storageRowCount")

    // Write into Kusto
    println(s"================Write into kusto at staging table : $stagingTable ==================================")

    dfStorageRead.write
      .format("com.microsoft.kusto.spark.synapse.datasource")
      .option("kustoDatabase", database)
      .option("kustoCluster", cluster)
      .option("kustoTable", stagingTable)
      .option(KustoSinkOptions.KUSTO_TABLE_CREATE_OPTIONS, "CreateIfNotExist")
      .option(KustoSinkOptions.KUSTO_WRITE_ENABLE_ASYNC, "false")
      .option(KustoSinkOptions.KUSTO_CLIENT_BATCHING_LIMIT, "1024")
      .mode("Append")
      .save()

    println(s"================  Restrict view access policy on table : $stagingTable ==================================")
    runKustoCommand(
      KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("restricttableviewaccess", table = stagingTable)),
      "Failed to restrict view access on staging table")

    println(s"================ Move the table : $stagingTable  to internal folder ==================================")
     runKustoCommand(
      KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("altertablefolder", table = stagingTable)),
      "Moving table to internal folder failed")

    // Validate the data rows in kusto is equal to the one in the staging table
    validateKustoRowCount(stagingTable, storageRowCount)

    // Create main table with staging table and restrict it's view access policy
    if (!isTableExists(mainTable)) {
      println(s"================ Create a prod table : $mainTable  from : $stagingTable ==================================")
      runKustoCommand(
        KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("createtable", table = stagingTable, destinationTable = mainTable)),
        "Create main table failed")

      println(s"================ Restrict view access policy on table : $mainTable ==================================")
      runKustoCommand(
        KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("restricttableviewaccess", table = mainTable)),
        "Failed while restricting main table view access")
    }

    println(s"================  Unrestrict view access policy on table : $stagingTable ==================================")
    runKustoCommand(
      KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("unrestricttableviewaccess", table = stagingTable)),
      "Failed to unrestrict view access on staging table")

    // Rename the staging to main table
    println(s"================ Rename table : $stagingTable to $mainTable ==================================")
    runKustoCommand(
      KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("renametables", table = stagingTable, destinationTable = mainTable)),
      "Rename table failed")

    Thread.sleep(5000) // Adding 5 s sleep
    // Validate the data rows in kusto is equal to the one in the main table
    validateKustoRowCount(mainTable, storageRowCount)

    // Drop the staging table
    println(s"================Drop  table: $stagingTable ==================================")
    runKustoCommand(
      KustoCommandBuilder.buildKustoJson(database, KustoCommandBuilder.buildQuery("droptable", table = stagingTable)),
      "Drop tables failed")

    val endTime = System.nanoTime()
    val durationInMs = (endTime - startTime) / 1e6 // Convert nanoseconds to milliseconds
    val durationInHours = durationInMs / (1000 * 60 * 60) // Convert milliseconds to hours

    println(s"Kusto ingestion executed in $durationInHours hours")
  }
}

// Orchestrator which does the ingestion
val mainTablePrefix = "Main_" + datasetName
val stagingTablePrefix = "Staging_" + datasetName
val viewName = datasetName

println("-------------------Start loading the data on ADX cluster -----------------------------------")

for (p <- partitionListToBeLoaded) {
  val partition = p.partition
  val paths      = p.paths
  val runId     = p.runId

  println(s"Partition=$partition, RunId=$runId")

  val isWatermarkPresent  = wmRepository.hasMatchingWatermark(runId = runId, partition = partition)
  if (isWatermarkPresent) {
    println(s"----------WaterMark entry is present for Partition=$partition, RunId=$runId. Skipping ADX load-------------")
  } else {
    var mainTable = mainTablePrefix
    var stagingTable = stagingTablePrefix

    // If dataset is partitioned, then the tables is datsetName + "_ "+ partition 
    if (isPartitionedDataset) {
      mainTable = mainTablePrefix + "_" + partition
      stagingTable = stagingTablePrefix + "_" + partition
    }

    val storagePaths = paths
    val ingestionManager = new KustoIngestionManager(spark, cluster, database, stagingTable, mainTable)
    ingestionManager.ingest(storagePaths)
    // Insert into watermark
    val wmProperties = DefaultWatermarkProperties(partition,runId)
    wmRepository.save(wmProperties, defaultwmPropertiesHandler)
  }
}

