# Fail script if any command fails
# $ErrorActionPreference = "Stop"

# Assign script params to parameters object variable.
# NOTE: Parameters are passed as base64(JSON) from Bicep to avoid command-line escaping issues.
$rawArg = if ($args.Count -eq 0) {
    ''
}
elseif ($args.Count -eq 1) {
    $args[0]
}
else {
    # Shouldn't happen with base64 arguments, but keep a reasonable fallback.
    $args -join ' '
}

if (-not [string]::IsNullOrEmpty($rawArg)) {
    $rawArg = $rawArg.Trim('"').Trim("'")
}

function Get-ParamsObjectFromArg {
    param(
        [Parameter(Mandatory = $true)][string] $Arg
    )

    if ([string]::IsNullOrWhiteSpace($Arg)) {
        throw "No parameters were provided to the deployment script."
    }

    # Preferred path: base64(JSON)
    try {
        $decoded = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($Arg))
        return ($decoded | ConvertFrom-Json -Depth 100)
    }
    catch {
        # Backward-compatible fallback: raw JSON
        return ($Arg | ConvertFrom-Json -Depth 100)
    }
}

$parameters = Get-ParamsObjectFromArg -Arg $rawArg

$subscriptionId = $parameters.subscriptionId
$synapseWorkspaceName = $parameters.synapseWorkspaceName
$kustoSnapshotLoadNotebookFile = "KustoSnapshotLoadUsingIndexFile.ipynb"
