    -Name $linkedServiceName `
    -DefinitionFile $definitionFile `
    -ErrorAction Stop

Write-Host "✅ Linked service '$linkedServiceName' deployed successfully."

# -----------------------------------
# Prepare Dataset JSON
# -----------------------------------
$datasetFile = "$datasetName.json"

$parameters.datasetFileContent |
ConvertTo-Json -Depth 100 -Compress |
Out-File $datasetFile -Encoding utf8

# -----------------------------------
# Deploy Dataset to Synapse
# -----------------------------------
Set-AzSynapseDataset `
    -WorkspaceName $synapseWorkspaceName `
    -Name $datasetName `
    -DefinitionFile $datasetFile `
    -ErrorAction Stop

Write-Host "✅ Dataset '$datasetName' created successfully."

# Determine Manifest File Path for the pipeline
$manifestFilePath = if ($attachToCentralDatalake -and -not [string]::IsNullOrWhiteSpace($centralManifestPath)) {
    $centralManifestPath
}
else {
    # Default to the one we are about to upload
    # Format: abfss://<container>@<storageAccount>.dfs.core.windows.net/<path>
    "abfss://$targetContainer@$storageAccountName.dfs.core.windows.net/$targetBlobPath"
}

$pipelineName = "KustoIngestionPipeline"
$synapseKustoIngestionPipelineContent.Replace(
    "<storageAccountName>",
    $storageAccountName
).Replace(
    "<storageEnvironmentSuffix>",
    $environmentSuffix.storage
).Replace(
    "<manifestFilePath>",
    $manifestFilePath
) | Out-File $synapseKustoIngestionPipelineFile -Encoding utf8

Write-Host "Uploading pipeline '$pipelineName' to Synapse workspace '$synapseWorkspaceName'..."
Set-AzSynapsePipeline  -WorkspaceName $synapseWorkspaceName -Name $pipelineName -DefinitionFile $synapseKustoIngestionPipelineFile

if ($?) {
    Write-Output "Pipeline '$pipelineName' successfully created in Synapse workspace '$synapseWorkspaceName'."
}
else {
    Write-Error "Failed to create pipeline '$pipelineName'."
    exit 1
}

# -------------------------------------
# Deploy the KustoOrchestrator Pipeline
# -------------------------------------
$pipelineName = "KustoOrchestratorPipeline"
$synapseKustoOrchestratorPipelineContent.Replace(
    "<storageAccountName>",
    $storageAccountName
).Replace(
    "<storageEnvironmentSuffix>",
    $environmentSuffix.storage
).Replace(
    "<kustoClusterName>",
    $kustoClusterName
) | Out-File $synapseKustoOrchestratorPipelineFile -Encoding utf8

Write-Host "Uploading pipeline '$pipelineName' to Synapse workspace '$synapseWorkspaceName'..."
Set-AzSynapsePipeline  -WorkspaceName $synapseWorkspaceName -Name $pipelineName -DefinitionFile $synapseKustoOrchestratorPipelineFile

if ($?) {
    Write-Output "Pipeline '$pipelineName' successfully created in Synapse workspace '$synapseWorkspaceName'."
}
else {
    Write-Error "Failed to create pipeline '$pipelineName'."
    exit 1
}

# -------------------------------
# Deploy the Trigger
# -------------------------------

$triggerName = "KustoCopyPipelineTrigger"

Write-Host "Uploading trigger '$triggerName'..."

Set-AzSynapseTrigger `
    -WorkspaceName $synapseWorkspaceName `
    -Name $triggerName `
    -DefinitionFile $triggerFile

if ($?) {
    Write-Output "Trigger '$triggerName' successfully created or updated."
}
else {
    Write-Error "Failed to create trigger '$triggerName'."
    exit 1
}

# if ($?) {
#     Write-Output "Trigger '$triggerName' started successfully."
# } else {
#     Write-Error "Trigger '$triggerName' could not be started."
#     exit 1
# }

# -----------------------------------
# Upload subscription-catalog.json to Blob Storage
# -----------------------------------

# Generate timestamp in ISO 8601 extended format (UTC)
$formattedTimestamp = (Get-Date).ToUniversalTime().ToString("yyyy-MM-ddTHH:mm:ssZ")

# Update Subscriber Info
if ($null -ne $catalogJson.subscriber) {
    Write-Host "Updating subscriber info..."
    $catalogJson.subscriber.tenant_id = $tenantId
    $catalogJson.subscriber.subscription_id = $subscriptionId
    $catalogJson.subscriber.last_updated_at = $formattedTimestamp
}

# Filter Data Products based on input array
if ($null -ne $catalogJson.data_products -and $null -ne $dataProductsArray) {
    Write-Host "Filtering data products to include only: $($dataProductsArray -join ', ')"
    $filteredProducts = @()
    foreach ($dp in $catalogJson.data_products) {
        if ($dataProductsArray -contains $dp.name) {
            $filteredProducts += $dp
        }
    }
    $catalogJson.data_products = $filteredProducts
    Write-Host "Filtered data products count: $($catalogJson.data_products.Count)"
}

# Filter Tables based on input datasets
if ($null -ne $catalogJson.data_products -and $null -ne $datasetsToDeploy) {
    Write-Host "Filtering tables within data products based on selected datasets object."
    foreach ($dp in $catalogJson.data_products) {
        if ($null -ne $dp.tables) {
            # Map Data Product name to its specific key in datasetsToDeploy object
            $dpKey = "datasets_$($dp.name)"
            $selectedDatasets = $datasetsToDeploy.$dpKey

            Write-Host "Processing Data Product: $($dp.name) using key: $dpKey. Selected datasets count: $($selectedDatasets.Count)"

            $filteredTables = @()
            foreach ($table in $dp.tables) {
                # Handle both string and object table definitions
                $tableName = if ($table -is [string]) { $table } else { $table.name }

                # Check match against the datasets selected for THIS specific Data Product
                if ($null -ne $selectedDatasets -and $selectedDatasets -contains $tableName) {
                    $filteredTables += $table
                }
            }
            $dp.tables = $filteredTables
            Write-Host "Remaining tables in $($dp.name): $($dp.tables.Count)"
        }
    }
}

if ($null -ne $storageAccountMap -and $null -ne $catalogJson.data_products) {
    Write-Host "Updating storage accounts in subscription-catalog.json..."
    foreach ($dp in $catalogJson.data_products) {
        # Check if we have mapped accounts for this data product name
        # Note: Bicep pass object keys as-is (Case "Charges", "Products").
        # JSON parsing in PS creates PSCustomObject. Properties lookup is generally case-insensitive in PS.
        if ($storageAccountMap.PSObject.Properties.Match($dp.name).Count -gt 0) {
            $accounts = $storageAccountMap.($dp.name)

            if ($null -ne $accounts -and $accounts.Count -gt 0) {
                Write-Host "Updating accounts for '$($dp.name)': found $($accounts.Count) accounts."

                # Update primary storage account
                if ($null -ne $dp.output_configuration) {
                    $dp.output_configuration.storage_account = $accounts[0]
                }

                # Update secondary storage accounts
                if ($accounts.Count -gt 1) {
                    # Skip the first one, take the rest
                    # PS slicing [1..($count-1)] works
                    $secondaries = $accounts[1..($accounts.Count - 1)]
                    $dp.output_configuration.additional_storage_accounts = $secondaries
                }
                else {
                    $dp.output_configuration.additional_storage_accounts = @()
                }
            }
            else {
                Write-Host "No accounts found in map for '$($dp.name)'."
            }
        }
    }
}

# Scenario: Attach to Central Manifest
if ($attachToCentralDatalake) {
    Write-Host "Trimming catalog for central manifest scenario..."
    foreach ($dp in $catalogJson.data_products) {
        Write-Host "Removing storage configuration from Data Product: $($dp.name)"
        $dp.PSObject.Properties.Remove("output_configuration")
    }
}

# Write content to local file (formatted)
$catalogJson | ConvertTo-Json -Depth 100 | Out-File $subscriptionCatalogFile -Encoding utf8

Write-Host "Uploading '$subscriptionCatalogFile' to container '$targetContainer' at path '$targetBlobPath' in storage account '$storageAccountName'..."

# Create storage context using Managed Identity
$ctx = New-AzStorageContext -StorageAccountName $storageAccountName -UseConnectedAccount

# Check if container exists, create if not
if (-not (Get-AzStorageContainer -Name $targetContainer -Context $ctx -ErrorAction SilentlyContinue)) {
    Write-Host "Container '$targetContainer' does not exist. Creating..."
    New-AzStorageContainer -Name $targetContainer -Context $ctx -Permission Off
}

# Upload full catalog
$filesToUpload = @(
    @{ Local = $subscriptionCatalogFile; Remote = $targetBlobPath }
)

foreach ($f in $filesToUpload) {
    Write-Host "Uploading '$($f.Local)' to '$targetContainer' at path '$($f.Remote)'..."
    Set-AzStorageBlobContent `
        -File $f.Local `
        -Container $targetContainer `
        -Blob $f.Remote `
        -Context $ctx `
        -Force

    if ($?) {
        Write-Output "File '$($f.Local)' successfully uploaded to '$targetContainer/$($f.Remote)'."
    }
    else {
        Write-Error "Failed to upload '$($f.Local)' to storage."
        exit 1
    }
}
